var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"MEMBER_HARMONY_PAST_NULL","text":{"KOREA":"으윽… 으으… 아, 아무것도 들리지 않아.","JPN":"ううっ……うう……な、何も聞こえない。","ENG":"Ugh... Gah... I-I can't hear anything.","TWN":"唉……唉……啊，我什麼也聽不見。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_HARMONY_PAST_NULL","text":{"KOREA":"귀… 내 귀가… 아아…","JPN":"耳……私の耳が……ああ……","ENG":"My... My ears... Ahhh...","TWN":"我的…….我的耳朵……啊……"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm.","TWN":"嗯。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"단원들의 비명소리가 들리기에 와보았더니…","JPN":"団員たちの悲鳴が聞こえたので来てみれば……","ENG":"I heard the members screaming, so I made my way here...","TWN":"我聽到團員的慘叫聲，就趕了過來……"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신이 이들을 이런 꼴로 만든 건가요?","JPN":"あなたが彼らをこのような姿に？","ENG":"Are you the one responsible for this?","TWN":"是你把她們弄成這樣的？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"예하께서… 말씀하셨어요.","JPN":"猊下が……おっしゃっていました。","ENG":"Her Eminence... told me.","TWN":"主教曾說過……"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"엘리시움 필하모닉은… 연주를 통해 세상 모든 것을 조율하려 한다고.","JPN":"エリシウムフィルハーモニーは……演奏を通じて世界のすべてを調律しようとしていると。","ENG":"The Elysium Philharmonic... tries to tune everything in this world through their performance.","TWN":"愛樂組織……是透過演奏來調和世界。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그러니… 아무것도 듣지 못한다면, 당신들은 더 이상 아무것도 연주할 수 없겠죠.","JPN":"だから……聴力を失えば、あなたたちはもう演奏できないでしょう。","ENG":"So... if you can't hear anything, you won't be able to play any instruments.","TWN":"所以……如果你聽不到任何聲音，你就不能再繼續演奏了。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"우리의 조율은 세계의 종말을 막기 위한 수단입니다.","JPN":"私たちの調律は、世界の終末を止めるための手段です。","ENG":"Our tuning is our way to stop the apocalypse.","TWN":"我們的調和是阻止世界末日的手段。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그래서… 사람들을 멋대로 희생시킨 건가요?","JPN":"だから……勝手に人々を犠牲にしたんですか？","ENG":"Is that why... you sacrificed people against their will?","TWN":"所以你……任意地犧牲了別人？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"세상을 구하려고… 제 언니를 그렇게 만든 건가요?","JPN":"世界を救うため……私のお姉さんをこんな姿にしたんですか？","ENG":"Did you do that to my sister too...? To save the world?","TWN":"為了拯救世界……對我姊姊做了那種事？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"다음 악장을 위해 끊어진 현을 갈아야 하듯, 실험에도 항상 새로운 자원이 필요합니다.","JPN":"次の楽章のために切れた弦を取り替えるように、実験にも常に新しい資源が必要です。","ENG":"A broken string must be replaced for the next movement, much like how experiments require new resources.","TWN":"要展開下一個樂章，就必須先換掉斷掉的弦，實驗也是需要新的資源的。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하께서도 모든 사실을 알고 계시지만, 이를 묵인하고 계신 걸요.","JPN":"猊下はすべての事実を知りながらも、これを黙認なさっているのです。","ENG":"Her Eminence is aware of all of this, but she has done nothing to stop us.","TWN":"主教也知道這一切，但是她默許了。"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그런데 고작 당신 한 명이 세상을 구하려는 우리 숭고한 연구를 방해할 셈인가요?","JPN":"なのに、たかがあなた一人で世界を救おうとする私たちの崇高な研究を邪魔するつもりですか？","ENG":"So, are you going to interfere with our noble research to save the world, alone?","TWN":"而就憑你一個人想要妨礙我們為拯救世界而展開的崇高研究嗎？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"세상을 구한다고요? 그런 게 저에게 무슨 의미가 있죠?","JPN":"世界を救う？　そんなこと、私に何の意味があるの？","ENG":"Save the world? That doesn't mean anything to me.","TWN":"拯救世界？這對我有什麼意義？"},"stage":{"bg":"LABORATORY_02","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>내 세상은… 이미 당신들에게 짓밟히고 없는데.</color>","JPN":"<color=#ff3636>私の世界は……すでにあなたたちに踏みにじられてなくなったのに。</color>","ENG":"<color=#ff3636>My whole world... has already been crushed by you people.</color>","TWN":"<color=#ff3636>我的世界……早已被你們踩在腳底下。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};